const dependent_vowels = new Set(["್", "ಾ", "ಿ", "ೀ", "ು", "ೂ", "ೃ", "ೆ", "ೇ", "ೈ", "ೊ", "ೋ", "ೌ"]);

export function unicodeToNudiASCII(text: string): string {
  if (!text) return "";
  return text.split(" ").map(processWord).join(" ");
}

function processWord(word: string): string {
  // If the word contains no Kannada characters, return as is.
  const hasKannada = /[\u0C80-\u0CFF]/.test(word);
  if (!hasKannada) {
    return word;
  }
  
  const chars = Array.from(word);
  let i = 0;
  const processed: string[] = [];
  
  while (i < chars.length) {
    const c = chars[i];
    
    // Check if we have a consonant followed by virama + consonant
    if (i + 2 < chars.length && chars[i+1] === "್" && vattaksharagalu[chars[i+2]]) {
      const base = c;
      const sub = chars[i+2];
      
      let nextIdx = i + 3;
      const subs = [sub];
      
      // Accumulate multiple subscripts (e.g. ಕ್ಟ್ರ -> ಕ + ್ + ಟ + ್ + ರ)
      while (nextIdx + 1 < chars.length && chars[nextIdx] === "್" && vattaksharagalu[chars[nextIdx+1]]) {
        subs.push(chars[nextIdx+1]);
        nextIdx += 2;
      }
      
      let vowel = "";
      if (nextIdx < chars.length && dependent_vowels.has(chars[nextIdx])) {
        vowel = chars[nextIdx];
        nextIdx += 1;
      }
      
      // Re-order: Base consonant + Vowel Sign + Subscript 1 + Subscript 2 ...
      processed.push(base + vowel);
      subs.forEach(s => {
        processed.push(vattaksharagalu[s]);
      });
      
      i = nextIdx;
    } else {
      processed.push(c);
      i++;
    }
  }
  
  const resolvedString = processed.join("");
  let j = 0;
  let result = "";
  
  while (j < resolvedString.length) {
    let matchFound = false;
    for (let len = 5; len >= 1; len--) {
      if (j + len <= resolvedString.length) {
        const sub = resolvedString.substring(j, j + len);
        if (mapping[sub]) {
          result += mapping[sub];
          j += len;
          matchFound = true;
          break;
        }
      }
    }
    
    if (!matchFound) {
      const char = resolvedString[j];
      result += char;
      j++;
    }
  }
  
  return result;
}
